module RefModule (
    input clk,
    input rst,
    input load,
    input [6:0] d,
    output [6:0] q
);

    reg [6:0] obf_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_q_reg <= 7'b0000000;
        else if (load)
            obf_q_reg <= d;
        else
            obf_q_reg <= obf_q_reg + 1;
    end

    assign q = obf_q_reg;

endmodule
